import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

const ProjectForm = () => {
    const { id } = useParams();
    const [project, setProject] = useState({
        name: '',
        description: '',
        status: 'active',
        client: '',
        start_date: '',
        end_date: ''
    });
    const [clients, setClients] = useState([]); // Список клиентов
    const navigate = useNavigate();

    // Получаем список клиентов
    useEffect(() => {
        const fetchClients = async () => {
            try {
                const token = localStorage.getItem('access_token');
                const response = await axios.get(`${process.env.REACT_APP_API_URL}/api/projects/clients/`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setClients(response.data);
            } catch (error) {
                console.error('Error fetching clients:', error);
            }
        };
        fetchClients();

        if (id) {
            fetchProject();
        }
    }, [id]);

    // Получаем данные проекта для редактирования
    const fetchProject = async () => {
        try {
            const token = localStorage.getItem('access_token');
            const response = await axios.get(`${process.env.REACT_APP_API_URL}/api/projects/${id}/`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setProject(response.data);
        } catch (error) {
            console.error('Error fetching project:', error);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const token = localStorage.getItem('access_token');
            const url = id
                ? `${process.env.REACT_APP_API_URL}/api/projects/${id}/update/`
                : `${process.env.REACT_APP_API_URL}/api/projects/create/`;

            const method = id ? 'put' : 'post';

            await axios[method](url, project, {
                headers: { Authorization: `Bearer ${token}` }
            });

            alert(id ? 'Project updated successfully!' : 'Project created successfully!');
            navigate('/projects/admin');
        } catch (error) {
            console.error('Error saving project:', error);
            alert('Failed to save project.');
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <h1>{id ? 'Edit Project' : 'Create Project'}</h1>
            <label>
                Name:
                <input
                    type="text"
                    value={project.name}
                    onChange={(e) => setProject({ ...project, name: e.target.value })}
                    required
                />
            </label>
            <br />
            <label>
                Description:
                <textarea
                    value={project.description}
                    onChange={(e) => setProject({ ...project, description: e.target.value })}
                    required
                />
            </label>
            <br />
            <label>
                Status:
                <select
                    value={project.status}
                    onChange={(e) => setProject({ ...project, status: e.target.value })}
                >
                    <option value="active">Active</option>
                    <option value="completed">Completed</option>
                </select>
            </label>
            <br />
            <label>
                Client:
                <select
                    value={project.client || ''}
                    onChange={(e) => setProject({ ...project, client: e.target.value })}
                    required
                >
                    <option value="">Select a client</option>
                    {clients.map((client) => (
                        <option key={client.id} value={client.id}>
                            {client.name}
                        </option>
                    ))}
                </select>
            </label>
            <br />
            <label>
                Start Date:
                <input
                    type="date"
                    value={project.start_date}
                    onChange={(e) => setProject({ ...project, start_date: e.target.value })}
                    required
                />
            </label>
            <br />
            <label>
                End Date:
                <input
                    type="date"
                    value={project.end_date}
                    onChange={(e) => setProject({ ...project, end_date: e.target.value })}
                />
            </label>
            <br />
            <button type="submit">{id ? 'Update' : 'Create'}</button>
        </form>
    );
};

export default ProjectForm;
